SourceCode.Declaration:
/// <summary>
/// Open Cust invoice import
/// </summary>
public class ETG_Acu_OpenCustInvoiceImport extends ETG_Acu_DataImportBase
{
    LedgerJournalId         journalNum;
}

Method.Source:
public static void main(Args args)
{
    ETG_Acu_OpenCustInvoiceImport  openCustInvoiceImport;

    openCustInvoiceImport = ETG_Acu_OpenCustInvoiceImport::construct();

    if (openCustInvoiceImport.prompt())
    {
        openCustInvoiceImport.runOperation();
    }
}

public static ETG_Acu_OpenCustInvoiceImport construct()
{
    return new ETG_Acu_OpenCustInvoiceImport();
}

/// <summary>
/// Describes whether the class is designed for execution in a new session.
/// </summary>
/// <returns>
/// true if the class is designed for execution the operation in a new session; otherwise, false.
/// </returns>
protected boolean canRunInNewSession()
{
    return false;
}

protected void processData(container _con)
{
    LedgerJournalEntity      ledgerJournal;

    NumberSeq               numberSeq;
    CustTable                   custTable;
    DirPartyBaseEntity          custTableDirParty;

    if (!journalNum)
    {
        numberSeq = NumberSeq::newGetNum(LedgerParameters::numRefJournalNum());

        journalNum = numberSeq.num();
    }

    select firstonly custTable
        exists join custTableDirParty
        where custTableDirParty.PartyRecordId  == custTable.Party
            && custTableDirParty.OrganizationNumber == conpeek(_con, 3);

    ledgerJournal.JournalBatchNumber            = journalNum;
    ledgerJournal.LineNumber                    = conpeek(_con, 2);
    ledgerJournal.AccountDisplayValue           = custTable.AccountNum;
    ledgerJournal.AccountType                   = LedgerJournalACType::Cust;
    ledgerJournal.CreditAmount                  = conpeek(_con, 5);
    ledgerJournal.CurrencyCode                  = conpeek(_con, 6);
    ledgerJournal.DebitAmount                   = conpeek(_con, 7);
    ledgerJournal.DefaultDimensionDisplayValue  = conpeek(_con, 8);
    ledgerJournal.Description                   = conpeek(_con, 9);
    ledgerJournal.Document                      = conpeek(_con, 10);
    ledgerJournal.DueDate                       = conpeek(_con, 11);
    ledgerJournal.ExchangeRate                  = conpeek(_con, 12);
    ledgerJournal.Invoice                       = conpeek(_con, 13);
    ledgerJournal.JournalName                   = conpeek(_con, 14);
    ledgerJournal.OffsetAccountDisplayValue     = conpeek(_con, 15) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                    + conPeek(_con, 26) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                    + conPeek(_con, 24) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                    + conPeek(_con, 28) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                    + conPeek(_con, 27) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                    + conPeek(_con, 22) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                    + conPeek(_con, 25) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                    + conPeek(_con, 23);
    ledgerJournal.OffsetAccountType             = conpeek(_con, 16);
    ledgerJournal.PostingLayer                  = conpeek(_con, 17);
    ledgerJournal.PostingProfile                = conpeek(_con, 18);
    ledgerJournal.Text                          = conpeek(_con, 19);
    ledgerJournal.TransDate                     = str2Date(conpeek(_con, 20), 123);

    // BusinessUnit (22)	Contract (23)	Department (24)	Intercompany (25)	Plant_Warehouse_Office (26)	Product_Service (27)	Trader_Employee (28)
    // |Plant_Warehouse_Office|Department|Trader_Employee|Product_Service|BusinessUnit|Intercompany|Contract

    ledgerJournal.DefaultDimensionDisplayValue  = conPeek(_con, 26) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 24) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 28) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 27) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 22) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 25) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 23);
    ledgerJournal.insert();
}

/// <summary>
///Import inventory site
/// </summary>
/// <returns>Caption</returns>
public ClassDescription caption()
{
    ClassDescription ret;

    ret = "@ETG_ENG_Labels:ImpOpenCustInvoice";

    return ret;
}
